class ElasticsearchClient:
    """Core Elasticsearch client wrapper for connection management."""

    def __init__(self, hosts: List[str] = None, **kwargs):
        self.hosts = hosts or ["http://localhost:9200"]
        self.client = None
        self._connect(**kwargs)

    def _connect(self, **kwargs):
        try:
            self.client = Elasticsearch(
                self.hosts,
                retry_on_timeout=True,
                max_retries=3,
                request_timeout=30,
                **kwargs
            )
            if self.client.ping():
                logger.info("Successfully connected to Elasticsearch cluster")
                info = self.client.info()
                logger.info(f"Cluster name: {info['cluster_name']}, Version: {info['version']['number']}")
            else:
                logger.error("Failed to ping Elasticsearch cluster")
                raise ConnectionError("Cannot ping Elasticsearch")
        except ConnectionError as e:
            logger.error(f"Connection error: {e}")
            raise

    def is_connected(self) -> bool:
        try:
            return self.client.ping()
        except Exception:
            return False

    def get_cluster_health(self) -> Dict:
        return self.client.cluster.health()

    def get_cluster_stats(self) -> Dict:
        return self.client.cluster.stats()


class IndexManager:
    """Manages Elasticsearch index operations."""

    def __init__(self, es_client: ElasticsearchClient):
        self.es = es_client.client

    def create_index(self, index_name: str, settings: Dict = None, mappings: Dict = None) -> bool:
        if self.es.indices.exists(index=index_name):
            logger.warning(f"Index '{index_name}' already exists")
            return False

        body = {}
        if settings:
            body["settings"] = settings
        if mappings:
            body["mappings"] = mappings

        self.es.indices.create(index=index_name, body=body)
        logger.info(f"Index '{index_name}' created successfully")
        return True

    def delete_index(self, index_name: str) -> bool:
        try:
            self.es.indices.delete(index=index_name)
            logger.info(f"Index '{index_name}' deleted successfully")
            return True
        except NotFoundError:
            logger.warning(f"Index '{index_name}' not found")
            return False

    def index_exists(self, index_name: str) -> bool:
        return self.es.indices.exists(index=index_name)

    def get_index_mapping(self, index_name: str) -> Dict:
        return self.es.indices.get_mapping(index=index_name)

    def update_mapping(self, index_name: str, properties: Dict) -> Dict:
        body = {"properties": properties}
        return self.es.indices.put_mapping(index=index_name, body=body)

    def refresh_index(self, index_name: str):
        self.es.indices.refresh(index=index_name)

    def list_indices(self, pattern: str = "*") -> List[str]:
        indices = self.es.indices.get(index=pattern)
        return list(indices.keys())

    def get_index_stats(self, index_name: str) -> Dict:
        return self.es.indices.stats(index=index_name)


class DocumentManager:
    """Handles document CRUD operations and bulk indexing."""

    def __init__(self, es_client: ElasticsearchClient):
        self.es = es_client.client

    def index_document(self, index_name: str, document: Dict, doc_id: str = None) -> Dict:
        kwargs = {"index": index_name, "body": document}
        if doc_id:
            kwargs["id"] = doc_id

        result = self.es.index(**kwargs)
        logger.debug(f"Document indexed: {result['_id']} in {index_name}")
        return result

    def get_document(self, index_name: str, doc_id: str) -> Optional[Dict]:
        try:
            result = self.es.get(index=index_name, id=doc_id)
            return result["_source"]
        except NotFoundError:
            logger.warning(f"Document {doc_id} not found in {index_name}")
            return None

    def update_document(self, index_name: str, doc_id: str, updates: Dict) -> Dict:
        body = {"doc": updates}
        return self.es.update(index=index_name, id=doc_id, body=body)

    def delete_document(self, index_name: str, doc_id: str) -> bool:
        try:
            self.es.delete(index=index_name, id=doc_id)
            logger.info(f"Document {doc_id} deleted from {index_name}")
            return True
        except NotFoundError:
            logger.warning(f"Document {doc_id} not found in {index_name}")
            return False

    def bulk_index(self, index_name: str, documents: List[Dict], id_field: str = None) -> Dict:
        actions = []
        for doc in documents:
            action = {
                "_index": index_name,
                "_source": doc
            }
            if id_field and id_field in doc:
                action["_id"] = doc[id_field]
            actions.append(action)

        success, errors = helpers.bulk(self.es, actions, raise_on_error=False, stats_only=False)
        logger.info(f"Bulk indexed {success} documents into {index_name}")
        if errors:
            logger.error(f"Bulk indexing errors: {len(errors)}")
        return {"success": success, "errors": errors}

    def bulk_index_with_pipeline(self, index_name: str, documents: List[Dict], pipeline: str) -> Dict:
        actions = []
        for doc in documents:
            action = {
                "_index": index_name,
                "_source": doc,
                "pipeline": pipeline
            }
            actions.append(action)

        success, errors = helpers.bulk(self.es, actions, raise_on_error=False)
        return {"success": success, "errors": errors}

    def count_documents(self, index_name: str, query: Dict = None) -> int:
        body = {"query": query} if query else None
        result = self.es.count(index=index_name, body=body)
        return result["count"]


